// DYNAMIC FIELD EXTRACTION + SCORING + CLEAN OUTPUT
const items = $input.all();

return items.map(item => {
  const task = item.json;
  const cf = task.custom_fields || [];

  // Helper: Find field by partial name
  const findField = (name) =>
    cf.find(f => f.name && f.name.toLowerCase().includes(name.toLowerCase()));

  // Dynamic lookup
  const scoreField = findField("score");
  const statusField = findField("status");
  const aiValidField = findField("valid");
  const lastCheckedField = findField("checked");
  const recField = findField("recommendation");
  const issueField = findField("issues");

  // Dynamic dropdown options
  const getOptionId = (field, optionName) => {
    if (!field?.type_config?.options) return null;
    const o = field.type_config.options
      .find(opt => opt.name.toLowerCase() === optionName.toLowerCase());
    return o?.id || null;
  };

  const f = {
    score: scoreField?.id || null,
    statusColor: statusField?.id || null,
    aiValid: aiValidField?.id || null,
    lastChecked: lastCheckedField?.id || null,
    aiRecommendation: recField?.id || null,
    aiKeyIssues: issueField?.id || null,

    redId: getOptionId(statusField, "red"),
    yellowId: getOptionId(statusField, "yellow"),
    greenId: getOptionId(statusField, "green"),

    aiValidYesId: getOptionId(aiValidField, "true") || getOptionId(aiValidField, "yes"),
    aiValidNoId: getOptionId(aiValidField, "false") || getOptionId(aiValidField, "no"),
  };

  // Extract metrics
  const completionField = findField("completion");
  const overdueField = findField("overdue");
  const blockersField = findField("blocker");

  const completion = Number(completionField?.value || 0);
  const overdue = Number(overdueField?.value || 0);
  const blockersText = blockersField?.value || "";
  const blockerCount = blockersText ? blockersText.split(",").filter(b => b.trim()).length : 0;

  // Scoring
  let systemStatus = "GREEN";
  let score = 90;

  if (completion < 50 || overdue > 3 || blockerCount > 1) {
    systemStatus = "RED";
    score = 25;
  } else if (completion < 80 || overdue >= 1 || blockerCount === 1) {
    systemStatus = "YELLOW";
    score = 60;
  }

  return {
    json: {
      taskId: task.id,
      projectName: task.name,
      completion,
      overdue,
      blockers: blockersText,
      blockerCount,
      systemStatus,
      score,
      fieldIds: f
    }
  };
});

const items = $input.all();

return items.map(item => {
  const out = {
    aiStatus: "UNKNOWN",
    aiValid: false,
    aiKeyIssues: "",
    risks: "",
    recommendedActions: "",
    aiError: null
  };

  let text;
  try {
    text = item.json.candidates[0].content.parts[0].text;
  } catch {
    out.aiError = "Failed to extract text";
    return { json: out };
  }

  try {
    const cleaned = text.replace(/```json|```/g, "").trim();
    const data = JSON.parse(cleaned);

    out.aiStatus = data.aiStatus;
    out.aiValid = data.isValid;
    out.aiKeyIssues = data.keyIssues;
    out.risks = data.risks;

    // Handle recommendedActions as array or string
    if (Array.isArray(data.recommendedActions)) {
      out.recommendedActions = data.recommendedActions.join("\n");
    } else {
      out.recommendedActions = data.recommendedActions || "";
    }

  } catch (e) {
    out.aiError = "AI returned invalid JSON: " + e.message;
  }

  return { json: out };
});

const items = $input.all();
const out = [];

for (const item of items) {
  const d = item.json;
  const f = d.fieldIds;

  if (!f || !f.score) continue;

  const statusOption = {
    RED: f.redId,
    YELLOW: f.yellowId,
    GREEN: f.greenId
  }[d.systemStatus];

  const validOption = d.aiValid ? f.aiValidYesId : f.aiValidNoId;

  const updates = [
    { id: f.score, val: d.score },
    { id: f.statusColor, val: statusOption },
    { id: f.lastChecked, val: Date.now() },
    { id: f.aiValid, val: validOption },
    { id: f.aiRecommendation, val: d.recommendedActions || "" },
    { id: f.aiKeyIssues, val: d.aiKeyIssues || "" }
  ];

  for (const u of updates) {
    if (u.id && u.val !== null && u.val !== undefined) {
      out.push({
        json: {
          taskId: d.taskId,
          fieldId: u.id,
          value: u.val
        }
      });
    }
  }
}

return out;

// CORRECTED: Maps dropdown option indices back to names
const items = $input.all();
const output = [];

// Map dropdown indices to values
const statusColorMap = { 0: "Green", 1: "Yellow", 2: "Red" };
const aiValidMap = { 0: "Yes", 1: "No" };

for (const item of items) {
  const task = item.json;

  // Helper: get custom field value AND handle both formats
  const getField = (name) => {
    const field = task.custom_fields?.find(f => 
      f.name.toLowerCase().includes(name.toLowerCase())
    );

    // Handle both string and numeric values
    if (!field) return "";
    if (typeof field.value === "number") return field.value.toString();
    return field.value || "";
  };

  // Extract fields
  const scoreRaw = getField("Score");
  const statusColorRaw = getField("Status Color");
  const aiValidRaw = getField("AI Valid");
  const aiKeyIssues = getField("Key Issues");
  const aiRecommendation = getField("Recommendation");
  const completion = getField("Completion %");
  const overdue = getField("Overdue Tasks");
  const blockers = getField("Blockers");

  // Convert numeric dropdown values to names
  const score = Number(scoreRaw) || 0;
  const statusColor = statusColorMap[Number(statusColorRaw)] || "UNKNOWN";
  const aiValid = aiValidMap[Number(aiValidRaw)] || "Unknown";

  // Determine notification type
  let notificationType = "NONE";

  // RED or YELLOW always need alerts
  if (statusColor === "Red" || statusColor === "Yellow") {
    notificationType = "STATUS_ALERT";
  }

  // GREEN projects with no AI data need manual review
  if (statusColor === "Green" && !aiKeyIssues && !aiRecommendation) {
    notificationType = "MANUAL_REVIEW";
  }

  const manualReviewDescription = 
    `⚠️ MANUAL REVIEW REQUIRED\n\nProject: ${task.name}\nStatus: ${statusColor}\nScore: ${score}/100\nCompletion: ${completion}%\nOverdue: ${overdue}\nBlockers: ${blockers || "None"}\n\nAI Assessment:\n${aiKeyIssues}\n\nRecommended Actions:\n${aiRecommendation}`;

  const statusAlertDescription =
    `🔔 PROJECT STATUS ALERT\n\nProject: ${task.name}\nStatus: ${statusColor}\nScore: ${score}/100\n\nIssues:\n${aiKeyIssues}\n\nNext Steps:\n${aiRecommendation}`;

  output.push({
    json: {
      taskId: task.id,
      taskName: task.name,
      taskUrl: task.url,
      systemStatus: statusColor,
      statusColor: statusColor,
      score: score,
      completion: completion,
      overdue: overdue,
      blockers: blockers,
      aiValid: aiValid,
      aiKeyIssues: aiKeyIssues,
      aiRecommendation: aiRecommendation,
      notificationType: notificationType,
      manualReviewDescription: manualReviewDescription,
      statusAlertDescription: statusAlertDescription
    }
  });
}

return output;

