// Aggregate Alerts (dedupe + flatten)
// Input: array of items where each item MAY have:
//   - taskId
//   - taskName/projectName
//   - systemStatus (RED/YELLOW/GREEN)
//   - notificationType: 'STATUS_ALERT' or 'MANUAL_REVIEW'
// Output: ONE item with arrays { statusAlerts, manualReviews }

const items = $input.all();

// helper to avoid undefined explosions
const get = (obj, ...keys) => {
  for (const k of keys) {
    if (!obj || typeof obj !== 'object') return undefined;
    obj = obj[k];
  }
  return obj;
};

// dedupe maps
const seenStatus = new Map();
const seenManual = new Map();

// normalize a task into safe minimal fields
const normalizeTask = (t) => ({
  taskId: t.taskId || t.id || get(t, 'id') || null,
  taskName: t.projectName || t.name || t.taskName || 'Unknown',
  score: t.score ?? t.systemScore ?? null,
  status: t.systemStatus || t.status || t.aiStatus || 'UNKNOWN',
  url: t.url || (t.taskId ? `https://app.clickup.com/t/${t.taskId}` : null),
  blockers: t.blockers || "",
  recommendedActions: t.recommendedActions || t.aiRecommendation || ""
});

// classification loop
for (const item of items) {
  const t = item.json;
  if (!t) continue;

  const nt = (t.notificationType || '').toUpperCase().trim();
  const ntask = normalizeTask(t);

  if (!ntask.taskId) continue;

  // status alerts: RED or YELLOW or explicitly tagged
  const sys = (ntask.status || '').toUpperCase();
  if (nt === 'STATUS_ALERT' || nt === 'STATUS' || sys === 'RED' || sys === 'YELLOW') {
    if (!seenStatus.has(ntask.taskId)) seenStatus.set(ntask.taskId, ntask);
  }

  // manual review
  if (nt === 'MANUAL_REVIEW' || nt === 'MANUAL') {
    if (!seenManual.has(ntask.taskId)) seenManual.set(ntask.taskId, ntask);
  }
}

// output = one single item
const statusAlerts = Array.from(seenStatus.values());
const manualReviews = Array.from(seenManual.values());

return [
  {
    json: {
      statusAlerts,
      manualReviews,
      statusAlertCount: statusAlerts.length,
      manualReviewCount: manualReviews.length
    }
  }
];

